// task: read parsed the JSON artifact into msg.result.artifactBody and the
// chaining ref into msg.result.outputRef. Lift the slots onto msg for the
// switch + the forecast URL builder; keep the outputRef for ADVISOR to chain.
const slots = (msg.result && msg.result.artifactBody) || {};
msg.intent = slots;
msg.intentRef = msg.result && msg.result.outputRef;
msg.proceed = slots.proceed === true;
return msg;

// Geocoding is out of scope for the demo: a tiny lookup table, default Lyon.
const COORDS = { lyon: [45.76, 4.84], paris: [48.85, 2.35], london: [51.51, -0.13], berlin: [52.52, 13.40] };
const key = String((msg.intent && msg.intent.location) || 'lyon').toLowerCase();
const [lat, lon] = COORDS[key] || COORDS.lyon;
msg.url =
  'https://api.open-meteo.com/v1/forecast?latitude=' + lat + '&longitude=' + lon +
  '&daily=temperature_2m_max,precipitation_probability_max&forecast_days=7&timezone=auto';
return msg;

// Carry the recommendation summary past the JUDGE payload overwrite, and keep
// the advisor outputRef (role: judged_work) for the JUDGE task to reference.
msg.recommendation = (msg.result && msg.result.summary) || (msg.payload && msg.payload.summary);
msg.advisorRef = msg.result && msg.result.outputRef;
return msg;

// task: read parsed the verdict JSON into msg.result.artifactBody.
const verdict = (msg.result && msg.result.artifactBody) || {};
msg.verdict = verdict;
msg.pass = verdict.pass === true;
return msg;
